package com.google.gson.internal.bind;
import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import com.google.gson.Gson;
import com.google.gson.TypeAdapter;
import com.google.gson.TypeAdapterFactory;
import com.google.gson.reflect.TypeToken;
import org.junit.jupiter.api.Test;

class TypeAdaptersTest {

  @Test
  void newFactory_createReturnsAdapterForMatchingType() {
    Class<String> type = String.class;
    @SuppressWarnings("unchecked")
    TypeAdapter<String> adapter = mock(TypeAdapter.class);

    TypeAdapterFactory factory = TypeAdapters.newFactory(type, adapter);

    Gson gson = mock(Gson.class);
    TypeToken<String> matchingTypeToken = TypeToken.get(String.class);
    TypeToken<Integer> nonMatchingTypeToken = TypeToken.get(Integer.class);

    // When type matches, should return the adapter casted to the generic type
    TypeAdapter<String> createdAdapter = factory.create(gson, matchingTypeToken);
    assertSame(adapter, createdAdapter);

    // When type does not match, should return null
    TypeAdapter<Integer> createdAdapterNull = factory.create(gson, nonMatchingTypeToken);
    assertNull(createdAdapterNull);
  }

  @Test
  void newFactory_toStringContainsTypeAndAdapter() {
    Class<Double> type = Double.class;
    @SuppressWarnings("unchecked")
    TypeAdapter<Double> adapter = mock(TypeAdapter.class);

    TypeAdapterFactory factory = TypeAdapters.newFactory(type, adapter);

    String toString = factory.toString();
    assertTrue(toString.contains(type.getName()));
    assertTrue(toString.contains(adapter.toString()));
  }
}
